units.exampleCode:
#include <iostream>
using namespace std;

int factorial(int n);

int factorial(int n) {
    int result = 1;
    for (int i = 1; i <= n; i++) {
        result *= i;
    }
    return result;
}

void printFactorials(int maxN) {
    for (int i = 1; i <= maxN; i++) {
        cout << i << "! = " << factorial(i) << endl;
    }
}

int main() {
    printFactorials(5);
    return 0;
}

