units.exampleCode:
#include <iostream>
using namespace std;

const int MAX_STUDENTS = 50;

double calcAverage(int scores[], int count);
void printResult(double avg);

double calcAverage(int scores[], int count) {
    int sum = 0;
    for (int i = 0; i < count; i++) {
        sum += scores[i];
    }
    return (double)sum / count;
}

void printResult(double avg) {
    cout << "平均分: " << avg << endl;
    if (avg >= 60) {
        cout << "整体及格" << endl;
    } else {
        cout << "整体不及格" << endl;
    }
}

int main() {
    int scores[] = {85, 72, 90, 58, 66};
    double avg = calcAverage(scores, 5);
    printResult(avg);
    return 0;
}

